fn build_query(filters: &[(String, String)]) -> String {
    let mut query = String::with_capacity(256);
    query.push_str("SELECT * FROM users WHERE 1=1");
    for (key, value) in filters {
        write!(&mut query, " AND {key} = '{value}'").unwrap();
    }
    query
}

