use std::io::{BufWriter, Write};

fn write_records(path: &str, records: &[Record]) -> std::io::Result<()> {
    let file = std::fs::File::create(path)?;
    let mut writer = BufWriter::new(file);
    for r in records {
        writeln!(writer, "{},{}", r.name, r.value)?;
    }
    writer.flush()
}

