use deadpool_postgres::{Config, Runtime};

let cfg = Config {
    host: Some("localhost".into()),
    dbname: Some("mydb".into()),
    ..Default::default()
};
let pool = cfg.create_pool(Some(Runtime::Tokio1), tokio_postgres::NoTls)?;

async fn get_user(pool: &Pool, id: i64) -> Result<User> {
    let client = pool.get().await?; // reuses existing connection
    let row = client.query_one("SELECT * FROM users WHERE id = $1", &[&id]).await?;
    Ok(User::from(row))
}

